#include <stdio.h>
#define DIM 4

int main() {
    int i, j;
    int matrica[DIM][DIM] = {
        {1, 2, 3, 4},
        {6, 7, 8, 9},
        {8, 7, 6, 5},
        {3, 2, 1, 1}
    };

    for (i = 1; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            matrica[i][j] += (-1) * matrica[i-1][j];
        }
    }
    
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            printf("%d ", matrica[i][j]);
        }
        printf("\n");
    }

    return 0;
}
